mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM TRIP
    WHERE trip_id = #{tripId}
)

SELECT EXISTS (
    SELECT 1
    FROM APP_USER
    WHERE user_id = #{userId}
)

SELECT *
FROM (
    SELECT

    FROM CHAT_MESSAGE cm
    JOIN APP_USER au ON cm.sender_user_id = au.user_id
    WHERE cm.trip_id = #{tripId}
    ORDER BY cm.created_at DESC, cm.message_id DESC
    LIMIT #{limit}
) recent_messages
ORDER BY createdAt ASC, messageId ASC
